const out = [];

for (const item of $input.all()) {
  const input = item?.json;

  const payload = (
    input &&
    typeof input === 'object' &&
    !Array.isArray(input) &&
    input.body &&
    typeof input.body === 'object'
  ) ? input.body : input;

  if (Array.isArray(payload)) {
    const closes = payload
      .map((r) => Number(Array.isArray(r) ? r[4] : r?.close ?? r?.p ?? r?.price))
      .filter((v) => Number.isFinite(v) && v > 0);

    if (closes.length === 0) {
      throw new Error(`Array payload received but no usable price found: ${JSON.stringify(payload).slice(0, 300)}`);
    }

    const price = closes[closes.length - 1];
    out.push({
      json: {
        symbol: 'BTCUSDT',
        price,
        eventType: 'array_payload',
        exchangeTime: Date.now(),
        receivedAt: new Date().toISOString(),
        raw: input,
      },
    });
    continue;
  }

  if (!payload || typeof payload !== 'object') {
    throw new Error(`Expected object payload, got: ${typeof payload}`);
  }

  const data = payload.data && typeof payload.data === 'object' ? payload.data : payload;
  const symbol = data.s || data.symbol || payload.symbol || 'BTCUSDT';

  const priceCandidates = [
    data.p,
    data.c,
    data.P,
    data.price,
    data.k?.c,
    payload.price,
    input?.price,
  ];

  const firstPrice = priceCandidates.find((x) => x !== undefined && x !== null && x !== '');
  if (firstPrice === undefined) {
    throw new Error(`Price could not be extracted from payload: ${JSON.stringify(input).slice(0, 500)}`);
  }

  const price = Number(firstPrice);
  if (!Number.isFinite(price) || price <= 0) {
    throw new Error(`Invalid price extracted: ${firstPrice}`);
  }

  out.push({
    json: {
      symbol,
      price,
      eventType: data.e || payload.e || 'unknown',
      exchangeTime: data.E || payload.E || Date.now(),
      receivedAt: payload.received_at || input?.received_at || new Date().toISOString(),
      raw: input,
    },
  });
}

return out;

const period = 14;
const panicThreshold = 2.0;

const out = [];
for (const item of $input.all()) {
  const { symbol, price } = item.json;

  const store = $getWorkflowStaticData('global');
  store.priceHistory = store.priceHistory || {};
  store.prevPrice = store.prevPrice || {};

  const history = store.priceHistory[symbol] || [];
  history.push(price);
  if (history.length > period + 50) history.shift();
  store.priceHistory[symbol] = history;

  let rsi = 50;
  if (history.length >= period + 1) {
    let gain = 0;
    let loss = 0;
    const start = history.length - (period + 1);
    for (let i = start + 1; i < history.length; i++) {
      const diff = history[i] - history[i - 1];
      if (diff >= 0) gain += diff; else loss += Math.abs(diff);
    }

    const avgGain = gain / period;
    const avgLoss = loss / period;
    if (avgLoss === 0) {
      rsi = 100;
    } else {
      const rs = avgGain / avgLoss;
      rsi = 100 - 100 / (1 + rs);
    }
  }

  const previous = store.prevPrice[symbol];
  store.prevPrice[symbol] = price;

  let movePct = 0;
  if (previous && previous > 0) {
    movePct = ((price - previous) / previous) * 100;
  }

  const isBearish = movePct <= -0.15 || rsi < 35;
  const isBullish = movePct >= 0.15 || rsi > 65;
  const panicScore = movePct <= -panicThreshold ? Math.min(100, Math.abs(movePct) * 20) : 0;

  out.push({
    json: {
      symbol,
      price,
      rsi: Number(rsi.toFixed(2)),
      is_bearish: isBearish,
      is_bullish: isBullish,
      panic_score: Number(panicScore.toFixed(2)),
    },
  });
}

return out;
